CREATE OR REPLACE FUNCTION fpb_get_control_id_by_group_no (as_group_no char , as_case char ) RETURNS varchar AS $body$
DECLARE

ls_return         varchar(400);
li_control_id     sc_mem_m_ucf_member_group.control_id%type;
ls_group_name     sc_mem_m_ucf_member_group.member_group_name%type;
ls_pre_group_name sc_mem_m_ucf_member_group.pre_group_name%type;


BEGIN
  begin
    select  member_group_name ,
            pre_group_name ,
            control_id
    into STRICT    ls_group_name ,
            ls_pre_group_name ,
            li_control_id
    from    sc_mem_m_ucf_member_group
    where   (member_group_no = (as_group_no));
  --EXCEPTION when others then spa_dberror('E18:ไม่พบข้อมูล');
  exception when others then return ' ';
  end;

  case trim(both as_case)
  when 'group_name' then
    ls_return := trim(both ls_group_name);
  when 'pre_group' then
    ls_return := ls_pre_group_name;
  when 'ctrl_id' then
    ls_return := li_control_id::text;
  else
    ls_return := ' ';
  end case;

  return coalesce(trim(both ls_return),' ');

  --exception when others then spa_dberror('FPB_GET_CONTROL_ID_BY_GROUP_NO');
  exception when others then return ' ';
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
